#include<bits/stdc++.h>
using namespace std;

int main() {
	long long b[6];
	long long c=0;
	for(long long i=0; i<6; i++) {
		string a;
		cin>>a;
		if(a=="one"||a=="a"||a=="first"||a=="another") {
			b[c]=1;
			c++;
		} else if(a=="two"||a=="both"||a=="second") {
			b[c]=4;
			c++;
		} else if(a=="three"||a=="third") {
			b[c]=9;
			c++;
		} else if(a=="four") {
			b[c]=16;
			c++;
		} else if(a=="five") {
			b[c]=25;
			c++;
		} else if(a=="six") {
			b[c]=36;
			c++;
		} else if(a=="seven") {
			b[c]=49;
			c++;
		} else if(a=="eight") {
			b[c]=64;
			c++;
		} else if(a=="nine") {
			b[c]=81;
			c++;
		} else if(a=="eleven") {
			b[c]=21;
			c++;
		} else if(a=="twelve") {
			b[c]=44;
			c++;
		} else if(a=="thirteen") {
			b[c]=69;
			c++;
		} else if(a=="fourteen") {
			b[c]=96;
			c++;
		} else if(a=="fifteen") {
			b[c]=25;
			c++;
		} else if(a=="sixteen") {
			b[c]=56;
			c++;
		} else if(a=="seventeen") {
			b[c]=89;
			c++;
		} else if(a=="eighteen") {
			b[c]=24;
			c++;
		} else if(a=="nineteen") {
			b[c]=61;
			c++;
		}
	}

	sort(b,b+c);
	long long r=0;
	for(long long i=0; i<c; i++) {
		r+=b[i];
		r*=100;
	}
	cout<<r/100;
	return 0;
}
